/**
 * @summary Verify a certificate using hash-based lookup (Bloom Filter optimized)
 */
export const getVerifyCertificateUrl = () => {
  return `/api/certificates/verify`;
};

export const verifyCertificate = async (
  verifyCertificateBody: VerifyCertificateBody,
  options?: RequestInit,
): Promise<VerificationResult> => {
  return customFetch<VerificationResult>(getVerifyCertificateUrl(), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(verifyCertificateBody),
  });
};

export const getVerifyCertificateMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof verifyCertificate>>,
    TError,
    { data: BodyType<VerifyCertificateBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof verifyCertificate>>,
  TError,
  { data: BodyType<VerifyCertificateBody> },
  TContext
> => {
  const mutationKey = ["verifyCertificate"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof verifyCertificate>>,
    { data: BodyType<VerifyCertificateBody> }
  > = (props) => {
    const { data } = props ?? {};

    return verifyCertificate(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

