/**
 * @summary List recent verification attempts
 */
export const getListVerificationsUrl = (params?: ListVerificationsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/verifications?${stringifiedParams}`
    : `/api/verifications`;
};

export const listVerifications = async (
  params?: ListVerificationsParams,
  options?: RequestInit,
): Promise<Verification[]> => {
  return customFetch<Verification[]>(getListVerificationsUrl(params), {
    ...options,
    method: "GET",
  });
};

